#include <bits/stdc++.h>using namespace std;int t;void solve(){	long long n;	cin>>n;	map<long long ,int>cnt;	for(int j=1;j<=n;j++){		long long x;		cin>>x;		for(long long i=2;i*i<=x;i++){			while(x%i==0){				cnt[i]++;				x/=i;			}		}		if(x>1)cnt[x]++;	}	int ans=0,odd=0;	for(auto const& [p,c]:cnt){		ans+=c/2;		odd+=c%2;	}	ans+=odd/3;	cout<<ans<<'\n';}int main(){	cin>>t;	while(t--)		solve();	return 0;}